-- ============================================================
-- System 5: ลดภาระครู — คลังตัวชี้วัดกลาง + กันตัวชี้วัดซ้ำ
-- Run AFTER supabase-system4-curriculum.sql
-- ============================================================

-- ---- 1. Prevent duplicate indicators per course (for library/import) ----
DELETE FROM indicators a USING indicators b
  WHERE a.id < b.id AND a.subject = b.subject AND a.code = b.code;
ALTER TABLE indicators DROP CONSTRAINT IF EXISTS indicators_subject_code_key;
ALTER TABLE indicators ADD CONSTRAINT indicators_subject_code_key UNIQUE (subject, code);

-- ---- 2. Master indicator library (national standard — shared bank) ----
CREATE TABLE IF NOT EXISTS indicator_library (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  subject_key TEXT NOT NULL,     -- grouping key, e.g. 'Math_P5'
  subject_label TEXT NOT NULL,   -- 'คณิตศาสตร์ ป.5'
  strand TEXT,
  standard TEXT NOT NULL,
  code TEXT NOT NULL,
  description TEXT NOT NULL,
  type TEXT NOT NULL CHECK (type IN ('interim', 'final')),
  key_concept TEXT,
  process TEXT,
  sequence_order INT DEFAULT 0,
  UNIQUE (subject_key, code)
);
ALTER TABLE indicator_library ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public read indicator_library" ON indicator_library FOR SELECT USING (true);
CREATE POLICY "Public insert indicator_library" ON indicator_library FOR INSERT WITH CHECK (true);

